```typescript
'use client';
import { useReadContract } from 'wagmi';
import { polkadotHubTestnet } from '../wagmi';

const STORAGE_ABI = [
  {
    inputs: [],
    name: 'retrieve',
    outputs: [{ internalType: 'uint256', name: '', type: 'uint256' }],
    stateMutability: 'view',
    type: 'function',
  },
] as const;

const CONTRACT_ADDRESS = '0xc01Ee7f10EA4aF4673cFff62710E1D7792aBa8f3' as `0x${string}`;

export function StorageRead() {
  const { data, isLoading } = useReadContract({
    address: CONTRACT_ADDRESS,
    abi: STORAGE_ABI,
    functionName: 'retrieve',
    chainId: polkadotHubTestnet.id,
  });

  return (
    <p>Stored value: {isLoading ? 'Loading...' : data?.toString() ?? 'N/A'}</p>
  );
}
```

The `as \`0x${string}\`` cast satisfies viem/wagmi's strict address type — without it, the literal string would type-check as `string` and cause a build failure on the `useReadContract({ address: ... })` call.

