```typescript
'use client';
import { useWriteContract, useAccount } from 'wagmi';
import { polkadotHubTestnet } from '../wagmi';
import { useState } from 'react';

const STORAGE_ABI = [
  {
    inputs: [{ internalType: 'uint256', name: 'num', type: 'uint256' }],
    name: 'store',
    outputs: [],
    stateMutability: 'nonpayable',
    type: 'function',
  },
] as const;

const CONTRACT_ADDRESS = '0xc01Ee7f10EA4aF4673cFff62710E1D7792aBa8f3' as `0x${string}`;

export function StorageWrite() {
  const { isConnected } = useAccount();
  const { writeContract, isPending, isSuccess } = useWriteContract();
  const [value, setValue] = useState('');

  const handleStore = () => {
    writeContract({
      address: CONTRACT_ADDRESS,
      abi: STORAGE_ABI,
      functionName: 'store',
      args: [BigInt(value)],
      chainId: polkadotHubTestnet.id,
    });
  };

  if (!isConnected) return <p>Connect your wallet to write.</p>;

  return (
    <div>
      <input value={value} onChange={e => setValue(e.target.value)} placeholder='Enter number' />
      <button onClick={handleStore} disabled={isPending}>
        {isPending ? 'Storing...' : 'Store'}
      </button>
      {isSuccess && <p>Transaction submitted!</p>}
    </div>
  );
}
```

Same address as step 6. This step requires a connected wallet (from step 3's `ConnectWallet`) and PAS tokens for the transaction fee — get tokens from <https://faucet.polkadot.io/>.

